#if UNITY_EDITOR
using System.Collections.Generic;
using UnityEditor;
using UnityEngine;

/// <summary>
/// Desenha uma lista de GameVariable (variáveis globais em GameVariables, ou
/// variáveis locais num NpcController) com nome, tipo e valor editáveis numa
/// única linha, mais um campo para adicionar uma nova variável — verificando
/// que o nome ainda não está em uso antes de a criar (Etapa 8).
///
/// Usado por GameVariablesEditor e NpcControllerEditor.
/// </summary>
public static class GameVariableListDrawer
{
    // Estado do campo "nova variável", indexado pelo propertyPath da lista
    // (para suportar várias listas — globais + locais de vários NPCs — ao
    // mesmo tempo sem misturar o texto introduzido).
    private static readonly Dictionary<string, string> _pendingNames = new Dictionary<string, string>();
    private static readonly Dictionary<string, VariableType> _pendingTypes = new Dictionary<string, VariableType>();
    private static readonly Dictionary<string, string> _errors = new Dictionary<string, string>();

    public static void Draw(SerializedProperty listProp, string title)
    {
        EditorGUILayout.LabelField(title, EditorStyles.boldLabel);

        if (listProp.arraySize > 0)
        {
            EditorGUILayout.BeginHorizontal();
            EditorGUILayout.LabelField("Nome", GUILayout.MinWidth(60));
            EditorGUILayout.LabelField("Tipo", GUILayout.Width(70));
            EditorGUILayout.LabelField("Valor", GUILayout.MinWidth(60));
            GUILayout.Space(24);
            EditorGUILayout.EndHorizontal();
        }

        int removeIndex = -1;

        for (int i = 0; i < listProp.arraySize; i++)
        {
            var element = listProp.GetArrayElementAtIndex(i);
            var nameProp = element.FindPropertyRelative("variableName");
            var typeProp = element.FindPropertyRelative("type");

            EditorGUILayout.BeginHorizontal();

            EditorGUILayout.PropertyField(nameProp, GUIContent.none, GUILayout.MinWidth(60));
            EditorGUILayout.PropertyField(typeProp, GUIContent.none, GUILayout.Width(70));

            switch ((VariableType)typeProp.enumValueIndex)
            {
                case VariableType.Bool:
                    EditorGUILayout.PropertyField(element.FindPropertyRelative("boolValue"), GUIContent.none, GUILayout.MinWidth(60));
                    break;
                case VariableType.Int:
                    EditorGUILayout.PropertyField(element.FindPropertyRelative("intValue"), GUIContent.none, GUILayout.MinWidth(60));
                    break;
                case VariableType.Float:
                    EditorGUILayout.PropertyField(element.FindPropertyRelative("floatValue"), GUIContent.none, GUILayout.MinWidth(60));
                    break;
                default:
                    EditorGUILayout.PropertyField(element.FindPropertyRelative("stringValue"), GUIContent.none, GUILayout.MinWidth(60));
                    break;
            }

            if (GUILayout.Button("X", GUILayout.Width(22)))
                removeIndex = i;

            EditorGUILayout.EndHorizontal();
        }

        if (removeIndex >= 0)
            listProp.DeleteArrayElementAtIndex(removeIndex);

        // ---- Adicionar nova variável ----

        string key = listProp.propertyPath;
        if (!_pendingNames.TryGetValue(key, out var pendingName)) pendingName = string.Empty;
        if (!_pendingTypes.TryGetValue(key, out var pendingType)) pendingType = VariableType.Bool;

        EditorGUILayout.BeginHorizontal();

        GUI.SetNextControlName("GameVariableNewName_" + key);
        pendingName = EditorGUILayout.TextField(pendingName);
        pendingType = (VariableType)EditorGUILayout.EnumPopup(pendingType, GUILayout.Width(70));

        if (GUILayout.Button("+ Adicionar Variável", GUILayout.Width(150)))
        {
            string trimmed = pendingName.Trim();

            if (string.IsNullOrEmpty(trimmed))
            {
                _errors[key] = "Define um nome para a variável.";
            }
            else if (NameExists(listProp, trimmed))
            {
                _errors[key] = $"Já existe uma variável chamada \"{trimmed}\". Escolhe outro nome.";
            }
            else
            {
                int newIndex = listProp.arraySize;
                listProp.arraySize++;

                var element = listProp.GetArrayElementAtIndex(newIndex);
                element.FindPropertyRelative("variableName").stringValue = trimmed;
                element.FindPropertyRelative("type").enumValueIndex = (int)pendingType;
                element.FindPropertyRelative("boolValue").boolValue = false;
                element.FindPropertyRelative("intValue").intValue = 0;
                element.FindPropertyRelative("floatValue").floatValue = 0f;
                element.FindPropertyRelative("stringValue").stringValue = string.Empty;

                _errors.Remove(key);
                pendingName = string.Empty;
                GUI.FocusControl(null);
            }
        }

        EditorGUILayout.EndHorizontal();

        _pendingNames[key] = pendingName;
        _pendingTypes[key] = pendingType;

        if (_errors.TryGetValue(key, out var error))
            EditorGUILayout.HelpBox(error, MessageType.Warning);

        EditorGUILayout.Space();
    }

    private static bool NameExists(SerializedProperty listProp, string name)
    {
        for (int i = 0; i < listProp.arraySize; i++)
        {
            var existing = listProp.GetArrayElementAtIndex(i).FindPropertyRelative("variableName").stringValue;
            if (existing == name) return true;
        }

        return false;
    }
}
#endif
